import{_ as e,c as o,a1 as t,o as r}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Another tools for Recon","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/7-Other-Tools.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/7-Other-Tools.md"}'),i={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/7-Other-Tools.md"};function n(s,a,l,c,h,d){return r(),o("div",null,a[0]||(a[0]=[t('<h1 id="another-tools-for-recon" tabindex="-1">Another tools for Recon <a class="header-anchor" href="#another-tools-for-recon" aria-label="Permalink to &quot;Another tools for Recon&quot;">​</a></h1><p>Sublist3r is a python tool designed to enumerate subdomains of websites using OSINT.</p><p><a href="https://github.com/aboul3la/Sublist3r" target="_blank" rel="noreferrer">https://github.com/aboul3la/Sublist3r</a></p><p>Log into your Kali machine and open the terminal</p><p>Type this command to update the Kali rolling packages and install sublist3r:</p><p><code>sudo apt update &amp;&amp; apt -y install sublist3r</code></p><p>Type <code>sublist3r -h</code> for print an overview of all options that are available.</p><blockquote><p>To search subdomains, type: <code>sublist3r -d google.com -t 3 -e bing</code><code>-d</code> = target domain <code>-t</code> = number of threads <code>-e</code> = search engine</p></blockquote><p>You also can find in which subdomain port 80 is open in <code>google.com</code> for example.</p><p><code>sublist3r -d google.com -p 80 -e bing</code></p><h1 id="web-data-extractor" tabindex="-1">Web Data Extractor <a class="header-anchor" href="#web-data-extractor" aria-label="Permalink to &quot;Web Data Extractor&quot;">​</a></h1><p>Web Data Extractor is used to extract a targeted company&#39;s contact details or data such as emails, fax, phone through web for responsible b2b communication.</p><p>This tool is exclusive for Windows, very easy to use. Downside: trial version export only 10 lines of report. <a href="http://www.webextractor.com/" target="_blank" rel="noreferrer">http://www.webextractor.com/</a></p><h1 id="httrack" tabindex="-1">HTTrack <a class="header-anchor" href="#httrack" aria-label="Permalink to &quot;HTTrack&quot;">​</a></h1><p>Web site copier is an offline browser utility that downloads a Web site to a local directory.</p><p>This application is available in GUI and CLI.</p><p>Works on Linux/OSX/BSD/Unix, Windows and Android. <a href="https://www.httrack.com/" target="_blank" rel="noreferrer">https://www.httrack.com/</a></p><h1 id="tracing-emails" tabindex="-1">Tracing Emails <a class="header-anchor" href="#tracing-emails" aria-label="Permalink to &quot;Tracing Emails&quot;">​</a></h1><p>Tracing emails involves analyzing the <strong>email header</strong> to discover details about the sender. Email tracking is useful for identifying the company and network providing service for the address.</p><p><strong>eMailTrackerPro</strong> is a tool to track, detect abnormalities in the email header. <a href="http://www.emailtrackerpro.com/" target="_blank" rel="noreferrer">http://www.emailtrackerpro.com/</a></p><h1 id="gathering-ip-and-domain-name-info-using-whois-lookup" tabindex="-1">Gathering IP and Domain Name info. using Whois Lookup <a class="header-anchor" href="#gathering-ip-and-domain-name-info-using-whois-lookup" aria-label="Permalink to &quot;Gathering IP and Domain Name info. using Whois Lookup&quot;">​</a></h1><p>Whois lookup reveals available information on a hostname, IP address or domain.</p><ul><li>For Windows: <a href="https://smartwhois.en.softonic.com/" target="_blank" rel="noreferrer"><strong>SmartWhois</strong></a></li><li>Kali Linux: <a href="https://www.cyberpratibha.com/blog/using-whois-a-command-for-information-gathering/" target="_blank" rel="noreferrer"><strong>whois command</strong></a></li></ul><h1 id="advanced-network-route-tracing-using-path-analyzer-pro" tabindex="-1">Advanced Network Route Tracing using Path Analyzer Pro <a class="header-anchor" href="#advanced-network-route-tracing-using-path-analyzer-pro" aria-label="Permalink to &quot;Advanced Network Route Tracing using Path Analyzer Pro&quot;">​</a></h1><p>Path Analyzer Pro delivers advanced network route tracing with performance tests, DNS, whois, and network resolution to investigate network issues.</p><p>Works on Linux/Mac/Windows. Paid application with 10-day trial version. <a href="https://www.pathanalyzer.com/" target="_blank" rel="noreferrer">https://www.pathanalyzer.com/</a></p><h1 id="automated-fingerprinting-using-foca" tabindex="-1">Automated Fingerprinting using FOCA <a class="header-anchor" href="#automated-fingerprinting-using-foca" aria-label="Permalink to &quot;Automated Fingerprinting using FOCA&quot;">​</a></h1><p>Fingerprinting Organizations with Collected Archives (FOCA) is a tool that reveals metadata and shrouded data. These archives may be on site pages, and can be downloaded and dissected with FOCA. <em>Official repository:</em> <a href="https://github.com/ElevenPaths/FOCA" target="_blank" rel="noreferrer">https://github.com/ElevenPaths/FOCA</a></p><p>Features:</p><ul><li>Metadata Extraction</li><li>Network Analysis</li><li>DNS Snooping</li><li>Search for common files</li><li>Juicy Files</li><li>Proxies Search</li><li>Technologies Identification</li><li>Fingerprinting</li><li>Leaks</li><li>Backups Search</li><li>Error Forcing</li><li>Open Directories Search</li></ul>',30)]))}const u=e(i,[["render",n]]);export{g as __pageData,u as default};
